class Solution {
    public String solveEquation(String equation) {
        int[] left = eval(equation.substring(0, equation.indexOf('=')));
        int[] right = eval(equation.substring(equation.indexOf('=') + 1));
        int LX = left[0], LY = left[1];
        int RX = right[0], RY = right[1];

        if (LX == RX) {
            if (LY == RY) return "Infinite solutions";
            else return "No solution";
        }

        return "x=" + (RY - LY) / (LX - RX);
    }

    private int[] eval(String s) {
        int X = 0, Y = 0;
        int num = 0;
        boolean positive = true;
        for (int i = 0; i < s.length(); i++) {
            char c = s.charAt(i);
            if (Character.isDigit(c)) {
                num = num * 10 + c - '0';
            } else if (c == 'x') {
                X += positive ? num : -num;
                num = 0;
                if (i == s.length() - 1 || s.charAt(i + 1) != '=') X++;
            } else if (c == '+') {
                Y += positive ? num : -num;
                num = 0;
                positive = true;
            } else if (c == '-') {
                Y += positive ? num : -num;
                num = 0;
                positive = false;
            }
        }
        Y += positive ? num : -num;
        return new int[]{X, Y};
    }
}
